import React, { useState } from 'react';
import axios from 'axios';
import { useAuth0 } from '@auth0/auth0-react';

function TradeForm(props) {
    const newDate = new Date()
    const date = (newDate.getMonth()+1)+'-'+newDate.getDate()+'-'+newDate.getFullYear()+'-'+newDate.getHours()+newDate.getMinutes()+newDate.getSeconds()+newDate.getMilliseconds()

    const [stock, setStock] = useState('MES')
    const [method,setMethod] = useState('Method')
    const [quantity, setQuantity] = useState(1)
    const [profitLoss, setProfitLoss] = useState(0)
    const {isAuthenticated} = useAuth0()


    const handleStock = e => {
        setStock({stock:e.target.value})     
    }
    const handleMethod = e => {
        setMethod(e.target.value)
    }
    const handleQuantity = e => {
        setQuantity(e.target.value)
    }
    const handleProfitLoss = e => {
        setProfitLoss(e.target.value)
    }

    const handleSubmit = e => {
        
        e.preventDefault()
        const newTrade = [{
            id:date,
            stock:stock,
            method:method,
            quantity:parseInt(quantity),
            profitLoss:parseFloat(profitLoss)
        }]
        if(isAuthenticated){
            axios.post('http://localhost:8888/trades', newTrade)
            .then(res => {
                console.log(res)
            })
            .catch(err => {
                console.log(err)
            })
            props.setTradeList([ ...newTrade, ...props.tradeList])         
        }
        else{
            alert('You must log in first')
        }
    }

    return(
        <form onSubmit={handleSubmit}>

            <p className='formLabel-buffer'></p>

            <select value={stock} onChange={handleStock} autoFocus>
                <option>MES</option>
            </select>
            <input value={method} onChange={handleMethod} type='text' />
            <input value={quantity} onChange={handleQuantity} type='number' min='1' step='1' />
            <input value={profitLoss} onChange={handleProfitLoss} type='number' step='0.25' className='input-profitLoss'/>

            <button type='submit'>+Trade</button>
        </form>  
    )
}

export default TradeForm;
